  it('should not add retain when inverting a delete op over base ops without attributes', () => {
    const base = new Delta().insert('hello');
    const delta = new Delta().delete(5);
    const inverted = delta.invert(base);
    // inverted should be insert('hello'), not insert('hello') + retain(...)
    expect(inverted.ops).toEqual([{ insert: 'hello' }]);
  });
});
```

