describe('Delta invert', () => {
  it('should correctly invert a retain with attributes operation', () => {
    const base = new Delta().insert('hello', { bold: true });
    const delta = new Delta().retain(5, { bold: null });
    const inverted = delta.invert(base);
    expect(inverted.ops).toEqual([{ retain: 5, attributes: { bold: true } }]);
  });
