describe('Delta invert', () => {
  it('should correctly invert a delete followed by retain with no attributes', () => {
    const base = new Delta().insert('hello world');
    const delta = new Delta().delete(5).retain(6);
    const inverted = delta.invert(base);
    expect(inverted.ops).toEqual([{ insert: 'hello' }, { retain: 6 }]);
  });
